exercise.solution:
let productName: string = "Laptop";
let price: number = 999;
let inStock = true;          // inferred as boolean
let tags = ["electronics", "sale"];  // inferred as string[]

console.log(`${productName} costs $${price}. In stock: ${inStock}. Tags: ${tags.join(", ")}`);
// Output: Laptop costs $999. In stock: true. Tags: electronics, sale
